<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">dictionary</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">cangjie6</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">#反查所得爲蒼頡碼</span></span>
